queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?position WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:position_id ?cg . ?child a :Creative_Position ; p:id ?cg . ?l p:agency_id ?pg . ?parent a :Marketing_Agency ; p:id ?pg . } GROUP BY ?child }
  ?child p:position ?position .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Marketing_Agency } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?position WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:position_id ?cg . ?child a :Creative_Position ; p:id ?cg . ?l p:agency_id ?pg . ?parent a :Marketing_Agency ; p:id ?pg . } GROUP BY ?child }
  ?child p:position ?position .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Marketing_Agency } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?position WHERE {
  ?marketing_agency_creative_positions a :Marketing_Agency_Creative_Positions .
  ?creative_position a :Creative_Position .
  ?marketing_agency_creative_positions p:hasCreative_Position ?creative_position .
  ?marketing_agency a :Marketing_Agency .
  ?marketing_agency_creative_positions p:hasMarketing_Agency ?marketing_agency .
  ?marketing_agency p:name ?name .
  ?creative_position p:position ?position .
} }
}
